#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "./main.h"
#include "./util/timer/timer.h"

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long time5;
    long long time6;

    time0 = get_time();

    time1 = get_time();

    time2 = get_time();

    time3 = get_time();

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    time4 = get_time();

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < dim.number_boxes; bx++) {
        int first_i = box[bx].offset;
        FOUR_VECTOR* rA = &rv[first_i];
        FOUR_VECTOR* fA = &fv[first_i];

        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
        for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
            rA_shared[wtx] = rA[wtx];
        }

        for (int k = 0; k < (1 + box[bx].nn); k++) {
            int pointer;
            if (k == 0) {
                pointer = bx;
            } else {
                pointer = box[bx].nei[k-1].number;
            }

            int first_j = box[pointer].offset;
            FOUR_VECTOR* rB = &rv[first_j];
            fp* qB = &qv[first_j];

            FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
            fp qB_shared[NUMBER_PAR_PER_BOX];

            for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
                rB_shared[wtx] = rB[wtx];
                qB_shared[wtx] = qB[wtx];
            }

            for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    fp r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT((fp)rA_shared[wtx], (fp)rB_shared[j]);
                    fp u2 = a2 * r2;
                    fp vij = exp(-u2);
                    fp fs = 2 * vij;

                    THREE_VECTOR d;
                    fp fxij, fyij, fzij;

                    d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
                    fxij = fs * d.x;
                    d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
                    fyij = fs * d.y;
                    d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
                    fzij = fs * d.z;

                    fA[wtx].v += (double)((fp)qB_shared[j] * vij);
                    fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
                    fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
                    fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
                }
            }
        }
    }

    time5 = get_time();

    time6 = get_time();

    printf("Time spent in different stages of CPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : CPU: SET DEVICE / DRIVER INIT\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU MEM: ALO\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU MEM: COPY IN\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU: KERNEL\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU MEM: COPY OUT\n", (float)(time5 - time4) / 1000000, (float)(time5 - time4) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU MEM: FRE\n", (float)(time6 - time5) / 1000000, (float)(time6 - time5) / (float)(time6 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time6 - time0) / 1000000);
}
